from spyne import Application, rpc, ServiceBase, Iterable, Integer, Unicode, Decimal, DateTime
from spyne.protocol.soap import Soap11
from spyne.server.wsgi import WsgiApplication
from spyne.model.complex import ComplexModel
from spyne.model.primitive import String, Integer as SpyneInteger
from datetime import datetime
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Define data models
class AccountInfo(ComplexModel):
    account_number = String
    account_holder = String
    account_type = String
    balance = Decimal

class TransferRequest(ComplexModel):
    from_account = String
    to_account = String
    amount = Decimal
    currency = String

class TransferResponse(ComplexModel):
    transaction_id = String
    status = String
    timestamp = DateTime

class BalanceResponse(ComplexModel):
    account_number = String
    balance = Decimal
    currency = String

# Mock database
accounts_db = {
    "12345": {"holder": "John Doe", "type": "Checking", "balance": 1000.00},
    "67890": {"holder": "Jane Smith", "type": "Savings", "balance": 2500.00},
    "54321": {"holder": "Bob Johnson", "type": "Checking", "balance": 500.00}
}

# Service implementation
class FinancialServices(ServiceBase):
    @rpc(String, _returns=AccountInfo)
    def getAccountInfo(ctx, account_number):
        logger.info(f"Getting account info for account {account_number}")
        if account_number in accounts_db:
            account = accounts_db[account_number]
            return AccountInfo(
                account_number=account_number,
                account_holder=account["holder"],
                account_type=account["type"],
                balance=account["balance"]
            )
        else:
            raise Exception(f"Account {account_number} not found")

    @rpc(String, _returns=BalanceResponse)
    def getBalance(ctx, account_number):
        logger.info(f"Getting balance for account {account_number}")
        if account_number in accounts_db:
            balance = accounts_db[account_number]["balance"]
            return BalanceResponse(
                account_number=account_number,
                balance=balance,
                currency="USD"
            )
        else:
            raise Exception(f"Account {account_number} not found")

    @rpc(TransferRequest, _returns=TransferResponse)
    def transferFunds(ctx, transfer_request):
        logger.info(f"Processing transfer from {transfer_request.from_account} to {transfer_request.to_account}")
        
        # Validate accounts exist
        if transfer_request.from_account not in accounts_db:
            raise Exception(f"Source account {transfer_request.from_account} not found")
        if transfer_request.to_account not in accounts_db:
            raise Exception(f"Destination account {transfer_request.to_account} not found")
        
        # Check sufficient funds
        from_balance = accounts_db[transfer_request.from_account]["balance"]
        if from_balance < transfer_request.amount:
            raise Exception("Insufficient funds")
        
        # Perform transfer
        accounts_db[transfer_request.from_account]["balance"] -= transfer_request.amount
        accounts_db[transfer_request.to_account]["balance"] += transfer_request.amount
        
        # Return response
        return TransferResponse(
            transaction_id=f"TXN_{datetime.now().strftime('%Y%m%d%H%M%S')}",
            status="SUCCESS",
            timestamp=datetime.now()
        )

# Create application
application = Application([FinancialServices], 
                         'http://financialservices.com/',
                         in_protocol=Soap11(validator='lxml'),
                         out_protocol=Soap11())

# Create WSGI application
wsgi_application = WsgiApplication(application)

